- 博弈論：Nim 遊戲、SG 函式
- 計算幾何：點線面、凸包
- 隨機演算法：蒙特卡羅、拒絕抽樣

**取模相關**：部分題目涉及取模運算，詳見 [模運算教程](https://leetcode.cn/circle/discuss/mDfnkW/)

**C++ 質數篩模板**：

```cpp
// 埃氏篩：篩出 [2, n] 的所有質數
vector<int> sieve(int n) {
    vector<int> primes;
    vector<bool> is_prime(n + 1, true);
    is_prime[0] = is_prime[1] = false;
    for (int p = 2; p <= n; ++p) {
        if (is_prime[p]) {
            primes.push_back(p);
            for (long long i = (long long)p * p; i <= n; i += p) { // 從 p² 開始篩 {
                is_prime[i] = false;
            }
            }
        }
    }
    return primes;
}
```

